import { Link, Outlet, useLocation } from "react-router-dom";
import "./style.scss"
function Account() {
    const location=useLocation()
    
    location.pathname===""
    return (
    <div className="page account-page">
        <div className="tab">
            <div className="tab-item tab-item-left" ><Link to={'/account/login'}>登录</Link></div>
            <div className="tab-item tab-item-right"><Link to={'/account/register'}>注册</Link></div>
        </div>
        <Outlet />
    </div>)

}


export default Account;
